/* ─── HELPERS ─── */
function Toast({ msg, onDone }) {
  useEffect(() => { const t = setTimeout(onDone, 3200); return () => clearTimeout(t); }, []);
  return <div className="toast">✓ {msg}</div>;
}
function Stars({ r }) {
  return <span>{"★".repeat(Math.round(r))}{"☆".repeat(5 - Math.round(r))}</span>;
}
function EmiCalc({ price }) {
  const [down, setDown] = useState(Math.round(price * 0.2));
  const [rate, setRate] = useState(8.5);
  const [months, setMonths] = useState(60);
  const loan = price - down, r = rate / 12 / 100;
  const emi = Math.round(loan * r * Math.pow(1+r,months) / (Math.pow(1+r,months) - 1));
  const total = emi * months, interest = total - loan;
  return (
    <div className="ecard">
      <div className="etit">EMI Calculator</div>
      {[["Down Payment",`₹${down.toLocaleString()}`,down,setDown,price*0.1,price*0.6,5000],["Interest Rate",`${rate}%`,rate,setRate,6,18,0.1],["Tenure",`${months} months`,months,setMonths,12,84,12]].map(([l,d,v,s,mn,mx,st])=>(
        <div className="esl" key={l}>
          <div className="erow"><span className="elbl">{l}</span><span className="eval">{d}</span></div>
          <input type="range" min={mn} max={mx} step={st} value={v} onChange={e=>s(Number(e.target.value))}/>
        </div>
      ))}
      <div className="eres">
        <div className="eri"><div className="erv hl">₹{emi.toLocaleString()}</div><div className="erl">Monthly EMI</div></div>
        <div className="eri"><div className="erv">₹{(interest/100000).toFixed(2)}L</div><div className="erl">Total Interest</div></div>
        <div className="eri"><div className="erv">₹{(total/100000).toFixed(2)}L</div><div className="erl">Total Amount</div></div>
      </div>
    </div>
  );
}

/* ─── CAR CARD ─── */
function CarCard({ car, onView, onWish, wishlisted, dark }) {
  return (
    <div className={dark ? "dc" : "cc"} onClick={() => onView(car)}>
      <div className="cc-img">
        <img src={car.img} alt={car.name} loading="lazy"/>
        {car.badge && <div className={`cbadge${car.fuel==="Electric"?" ev":car.category==="used"?" used":""}`}>{car.badge}</div>}
        <button className="wbtn" onClick={e=>{e.stopPropagation();onWish(car.id);}}>{wishlisted?"❤️":"🤍"}</button>
      </div>
      <div className="cc-body">
        <div className="cc-brand">{car.brand}</div>
        <div className="cc-name">{car.name}</div>
        <div className="cc-specs">
          <div className="cspec"><strong>{car.fuel}</strong>Fuel</div>
          <div className="cspec"><strong>{car.transmission.split(" ")[0]}</strong>Trans.</div>
          <div className="cspec"><strong>{car.mileage.split(" ")[0]}</strong>Mileage</div>
        </div>
        <div className="cc-foot">
          <div><div className="cprice">{fmt(car.price)} <small>onwards</small></div></div>
          <div style={{display:"flex",flexDirection:"column",alignItems:"flex-end",gap:4}}>
            <div className="crat"><Stars r={car.rating}/> {car.rating}</div>
            <button className="vnow" onClick={e=>{e.stopPropagation();onView(car);}}>View →</button>
          </div>
        </div>
      </div>
    </div>
  );
}

/* ─── AI CHAT ─── */
function AiChat() {
  const [open, setOpen] = useState(false);
  const [msgs, setMsgs] = useState([{role:"ai",text:"👋 Hi! I'm SarthiBot, your personal car advisor. Tell me your budget and what you're looking for — I'll find your perfect car!"}]);
  const [inp, setInp] = useState("");
  const [loading, setLoading] = useState(false);
  const botRef = useRef(null);
  useEffect(()=>{ botRef.current?.scrollIntoView({behavior:"smooth"}); },[msgs,loading]);

  const send = async () => {
    if (!inp.trim()||loading) return;
    const q = inp.trim(); setInp(""); setLoading(true);
    setMsgs(m=>[...m,{role:"user",text:q}]);
    try {
      const history = msgs.map(m=>({ role: m.role==="ai"?"model":"user", parts:[{text:m.text}] }));
      const res = await fetch(
        `https://generativelanguage.googleapis.com/v1beta/models/gemini-1.5-flash:generateContent?key=${GEMINI_KEY}`,
        { method:"POST", headers:{"Content-Type":"application/json"},
          body:JSON.stringify({
            system_instruction:{ parts:[{text:AI_SYS}] },
            contents:[...history, {role:"user", parts:[{text:q}]}],
            generationConfig:{ maxOutputTokens:300, temperature:0.75 }
          })
        }
      );
      const data = await res.json();
      const reply = data.candidates?.[0]?.content?.parts?.[0]?.text || "Sorry, I couldn't connect. Please try again!";
      setMsgs(m=>[...m,{role:"ai",text:reply}]);
    } catch(e) { setMsgs(m=>[...m,{role:"ai",text:"Connection error. Please try again."}]); }
    setLoading(false);
  };

  return (
    <>
      {open && (
        <div className="cwin">
          <div className="chd">
            <div className="chav">🤖</div>
            <div><div className="chn">SarthiBot</div><div className="chs">● Online • AI Car Advisor</div></div>
            <button className="ccl" onClick={()=>setOpen(false)}>×</button>
          </div>
          <div className="cmsgs">
            {msgs.map((m,i)=>(
              <div key={i} className={`cbw ${m.role}`}><div className="cbbl">{m.text}</div></div>
            ))}
            {loading && <div className="cbw ai"><div className="ctyp"><div className="td"/><div className="td"/><div className="td"/></div></div>}
            <div ref={botRef}/>
          </div>
          <div className="cib">
            <input className="cinp" placeholder="Ask about cars..." value={inp} onChange={e=>setInp(e.target.value)} onKeyDown={e=>e.key==="Enter"&&send()}/>
            <button className="csnd" onClick={send}>➤</button>
          </div>
        </div>
      )}
      <button className="cfab" onClick={()=>setOpen(o=>!o)}>{open?"✕":"🤖"}</button>
    </>
  );
}

/* ─── MODALS ─── */
function EditCarModal({car,onSave,onClose}) {
  const [f,setF] = useState({...car});
  const s=(k,v)=>setF(p=>({...p,[k]:v}));
  const fields=[["name","Car Name","text"],["brand","Brand","text"],["price","Price (₹)","number"],["type","Body Type","text"],["fuel","Fuel Type","text"],["transmission","Transmission","text"],["mileage","Mileage","text"],["engine","Engine","text"],["power","Power","text"],["torque","Torque","text"],["seats","Seats","number"],["year","Year","number"],["badge","Badge","text"]];
  return (
    <div className="mov" onClick={e=>e.target===e.currentTarget&&onClose()}>
      <div className="mdl">
        <div className="mhd"><div className="mtt">✏️ Edit — {car.name}</div><button className="mcl" onClick={onClose}>×</button></div>
        <div className="mbdy">
          <div className="mgrd">
            {fields.map(([k,l,t])=>(
              <div className="fg" key={k} style={["name","img"].includes(k)?{gridColumn:"span 2"}:{}}>
                <label className="fl">{l}</label>
                <input className="fi" type={t} value={f[k]||""} onChange={e=>s(k,t==="number"?Number(e.target.value):e.target.value)}/>
              </div>
            ))}
            <div className="fg" style={{gridColumn:"span 2"}}><label className="fl">Image URL</label><input className="fi" value={f.img||""} onChange={e=>s("img",e.target.value)} placeholder="https://..."/></div>
            <div className="fg"><label className="fl">Category</label><select className="fi" value={f.category} onChange={e=>s("category",e.target.value)}><option value="new">New</option><option value="used">Used</option></select></div>
            <div className="fg"><label className="fl">Featured</label><select className="fi" value={f.featured?"yes":"no"} onChange={e=>s("featured",e.target.value==="yes")}><option value="yes">Yes</option><option value="no">No</option></select></div>
          </div>
        </div>
        <div className="mft"><button className="aab" onClick={onClose}>Cancel</button><button className="aab pri" onClick={()=>onSave(f)}>Save Changes</button></div>
      </div>
    </div>
  );
}

