function ListingsPage({cars,user,setSelectedCar,setPage,toast,wishlist,onWish}) {
  const [q,setQ]=useState(""); const [brand,setBrand]=useState("All"); const [type,setType]=useState("All"); const [fuel,setFuel]=useState("All"); const [cat,setCat]=useState("all"); const [sort,setSort]=useState("default");
  const filtered = cars.filter(c=>(brand==="All"||c.brand===brand)&&(type==="All"||c.type===type)&&(fuel==="All"||c.fuel===fuel)&&(cat==="all"||c.category===cat)&&(c.name.toLowerCase().includes(q.toLowerCase())||c.brand.toLowerCase().includes(q.toLowerCase()))).sort((a,b)=>sort==="price-asc"?a.price-b.price:sort==="price-desc"?b.price-a.price:sort==="rating"?b.rating-a.rating:0);
  return (
    <div className="sec" style={{paddingTop:84}}>
      <div className="stop" style={{marginBottom:28}}><div><div className="sey">Browse</div><h2 className="stit">All <em>Cars</em></h2></div></div>
      <div className="tabs">{[["all","All Cars"],["new","New"],["used","Used"]].map(([v,l])=><button key={v} className={`tab ${cat===v?"act":""}`} onClick={()=>setCat(v)}>{l}</button>)}</div>
      <div className="fbar">
        <div className="fg2" style={{flex:1}}><div className="fl2">Search</div><input className="finp" placeholder="Search by name or brand..." value={q} onChange={e=>setQ(e.target.value)}/></div>
        {[["Brand",["All","Maruti Suzuki","Hyundai","Tata Motors","Honda","Kia","Toyota","BMW","Mahindra","Skoda","MG"],brand,setBrand],["Type",["All","Hatchback","Sedan","SUV","Electric SUV","Micro SUV"],type,setType],["Fuel",["All","Petrol","Diesel","Electric"],fuel,setFuel],["Sort",["default","price-asc","price-desc","rating"],sort,setSort,["Default","Price ↑","Price ↓","Best Rated"]]].map(([l,opts,val,setter,labels])=>(
          <div className="fg2" key={l}><div className="fl2">{l}</div><select className="fsel" value={val} onChange={e=>setter(e.target.value)}>{opts.map((o,i)=><option key={o} value={o}>{labels?labels[i]:o}</option>)}</select></div>
        ))}
      </div>
      <div className="cnt">{filtered.length} cars found</div>
      {filtered.length===0?<div className="nrz"><div className="nri">🔍</div><div style={{fontSize:17,fontWeight:800,marginBottom:7}}>No cars found</div><div>Try adjusting filters</div></div>:<div className="cgrid">{filtered.map(car=><CarCard key={car.id} car={car} onView={c=>{setSelectedCar(c);setPage("detail");}} onWish={id=>{if(!user){toast("Please login to save wishlist");return;}onWish(id);toast(wishlist.includes(id)?"Removed":"Added to wishlist ❤️");}} wishlisted={wishlist.includes(car.id)}/>)}</div>}
    </div>
  );
}

function DetailPage({car,setPage,toast,user,bookTestDrive}) {
  const [tab,setTab]=useState("specs"); const [booked,setBooked]=useState(false); const [booking,setBooking]=useState(false);
  if(!car)return null;
  const specs=[["Engine",car.engine],["Power",car.power],["Torque",car.torque],["Fuel",car.fuel],["Transmission",car.transmission],["Mileage",car.mileage],["Seats",`${car.seats} persons`],["Year",car.year],["Type",car.type]];
  return (
    <div className="dpage">
      <button className="bbtn" onClick={()=>setPage("listings")}>← Back</button>
      <div className="dgrd">
        <div className="dim"><img src={car.img} alt={car.name}/></div>
        <div>
          <div className="dbrand">{car.brand}</div>
          <div className="dtit">{car.name}</div>
          <div style={{display:"flex",alignItems:"center",gap:8,marginBottom:18}}>
            <span style={{color:"#D97706",fontSize:15}}><Stars r={car.rating}/></span>
            <span style={{fontWeight:800,color:"var(--dk)"}}>{car.rating}</span>
            <span style={{color:"var(--mt)",fontSize:12}}>({car.reviews.toLocaleString()} reviews)</span>
          </div>
          <div className="dpr">{fmt(car.price)} <small>onwards</small></div>
          <div style={{display:"flex",gap:6,flexWrap:"wrap",marginBottom:18}}>
            {[car.fuel,car.transmission,car.type,`${car.seats} Seats`].map(t=><span key={t} style={{background:"var(--off)",color:"var(--dk)",padding:"4px 11px",borderRadius:6,fontSize:11,fontWeight:700,border:"1px solid var(--bdr)"}}>{t}</span>)}
          </div>
          <div className="dacts">
            <button className="bkbtn" disabled={booked||booking} onClick={async()=>{if(!user){toast("Please login first");return;}setBooking(true);const ok=bookTestDrive?await bookTestDrive(car):true;if(ok){setBooked(true);toast("Test drive booked! 🎉");}setBooking(false);}}>{booked?"✓ Booked!":booking?"Booking...":"Book Test Drive"}</button>
            <button className="qtbtn" onClick={()=>toast("Connecting to nearest dealer...")}>Get Quote</button>
            <button className="qtbtn" onClick={()=>{setPage("compare");toast("Go to compare page!");}}>Compare</button>
          </div>
          {car.colors?.length>0&&<div><div style={{fontSize:11,color:"var(--mt)",fontWeight:700,textTransform:"uppercase",letterSpacing:"0.5px",marginBottom:7}}>Colors</div><div className="cdots">{car.colors.map(c=><div key={c} className="cdot" title={c} style={{background:c}}/>)}</div></div>}
        </div>
      </div>
      <div className="tabs">{[["specs","Specifications"],["features","Features"],["emi","EMI Calculator"]].map(([v,l])=><button key={v} className={`tab ${tab===v?"act":""}`} onClick={()=>setTab(v)}>{l}</button>)}</div>
      {tab==="specs"&&<div className="sgrid">{specs.map(([k,v])=><div className="si" key={k}><div className="sk">{k}</div><div className="sv">{v}</div></div>)}</div>}
      {tab==="features"&&<div style={{display:"grid",gridTemplateColumns:"repeat(auto-fill,minmax(190px,1fr))",gap:9}}>{["ABS + EBD","6 Airbags","Rear Camera","Cruise Control","Sunroof","Wireless Charging","Android Auto","Apple CarPlay","Auto Climate","TPMS","Hill Hold","Lane Warning","Keyless Entry","Push Start"].map(f=><div key={f} style={{display:"flex",alignItems:"center",gap:9,padding:"11px 14px",background:"var(--off)",borderRadius:9,border:"1px solid var(--bdr)",fontSize:12,fontWeight:600}}><span style={{color:"#059669",fontSize:14}}>✓</span>{f}</div>)}</div>}
      {tab==="emi"&&<EmiCalc price={car.price}/>}
    </div>
  );
}

function ComparePage({cars,toast}) {
  const [sel,setSel]=useState([cars[0],cars[1]]); const [pick,setPick]=useState(false);
  const tog=(car)=>{ if(sel.find(c=>c.id===car.id)){setSel(s=>s.filter(c=>c.id!==car.id));}else if(sel.length<3){setSel(s=>[...s,car]);}else{toast("Max 3 cars at a time");} setPick(false); };
  const rows=[["Price",c=>fmt(c.price)],["Engine",c=>c.engine],["Power",c=>c.power],["Torque",c=>c.torque],["Fuel",c=>c.fuel],["Transmission",c=>c.transmission],["Mileage",c=>c.mileage],["Seats",c=>c.seats],["Rating",c=>`★ ${c.rating}`],["Type",c=>c.type],["Year",c=>c.year]];
  return (
    <div className="sec" style={{paddingTop:84}}>
      <div className="sey">Analysis</div>
      <h2 className="stit" style={{marginBottom:36}}>Compare <em>Cars</em></h2>
      <div className="cprow">
        {sel.map(car=>(
          <div className="cppill" key={car.id}>
            <img src={car.img} alt={car.name}/>
            <div style={{flex:1}}><div style={{fontWeight:800,fontSize:13,color:"var(--dk)"}}>{car.name}</div><div style={{fontSize:11,color:"var(--r)",fontWeight:700}}>{fmt(car.price)}</div></div>
            <button onClick={()=>setSel(s=>s.filter(c=>c.id!==car.id))} style={{background:"none",border:"none",color:"var(--mt)",cursor:"pointer",fontSize:17,lineHeight:1}}>×</button>
          </div>
        ))}
        {sel.length<3&&<button className="cpadd" onClick={()=>setPick(true)}>+ Add Car</button>}
      </div>
      {pick&&(
        <div className="mov" onClick={()=>setPick(false)}>
          <div className="mdl" onClick={e=>e.stopPropagation()}>
            <div className="mhd"><div className="mtt">Select a Car</div><button className="mcl" onClick={()=>setPick(false)}>×</button></div>
            <div className="mbdy"><div style={{display:"grid",gridTemplateColumns:"1fr 1fr",gap:10}}>
              {cars.filter(c=>!sel.find(s=>s.id===c.id)).map(car=>(
                <div key={car.id} onClick={()=>tog(car)} style={{display:"flex",gap:10,alignItems:"center",padding:"11px 13px",background:"var(--off)",borderRadius:10,cursor:"pointer",border:"1.5px solid var(--bdr)",transition:"all 0.15s"}} onMouseEnter={e=>{e.currentTarget.style.borderColor="var(--r)";}} onMouseLeave={e=>{e.currentTarget.style.borderColor="var(--bdr)";}}>
                  <img src={car.img} style={{width:56,height:38,borderRadius:7,objectFit:"cover"}} alt={car.name}/>
                  <div><div style={{fontWeight:800,fontSize:12,color:"var(--dk)"}}>{car.name}</div><div style={{fontSize:11,color:"var(--r)",fontWeight:700}}>{fmt(car.price)}</div></div>
                </div>
              ))}
            </div></div>
          </div>
        </div>
      )}
      {sel.length>=2&&<div style={{overflowX:"auto"}}><table className="ctbl"><thead><tr><th style={{width:130}}>Feature</th>{sel.map(c=><th key={c.id}><div style={{display:"flex",alignItems:"center",gap:8}}><img src={c.img} style={{width:50,height:34,borderRadius:6,objectFit:"cover"}} alt={c.name}/>{c.name}</div></th>)}</tr></thead><tbody>{rows.map(([l,fn])=><tr key={l}><td style={{color:"var(--mt)",fontWeight:700,fontSize:11,textTransform:"uppercase",letterSpacing:"0.3px"}}>{l}</td>{sel.map(c=><td key={c.id} style={{fontWeight:600}}>{fn(c)}</td>)}</tr>)}</tbody></table></div>}
    </div>
  );
}

